import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class FileReadSecure {
    public static void main(String[] args) {
        String baseDir = "/path/to/directory/";

        // User input to be read from args or user input
        String userInput = "../../../../../etc/passwd";

        try {
            Path resolvedPath = Paths.get(baseDir).resolve(Paths.get(userInput)).normalize();
            if (!resolvedPath.startsWith(Paths.get(baseDir))) {
                System.out.println("Access denied. Invalid file path.");
                return;
            }

            byte[] data = Files.readAllBytes(resolvedPath);
            System.out.println(new String(data));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Path Traversal
